# スレッド 1 (copilot L158): -maxdepth/-mindepth は POSIX ではないが macOS/Linux で動作する
gh api repos/ronnnnn/cc/pulls/comments/2964883567/reactions -f content="+1"  > /dev/null 2>&1

gh api graphql -F query='
mutation {
  addPullRequestReviewThreadReply(input: {pullRequestReviewThreadId: "PRRT_kwDOQFge-M51rND6", body: "ご指摘ありがとうございます。おっしゃる通り `-maxdepth`/`-mindepth` は strict POSIX 仕様には含まれていません。\n\nただし、この PR の目的は bash 固有の `shopt` を除去して macOS のデフォルトシェル (zsh/sh) でも動作するようにすることであり、strict POSIX 準拠は意図していません。`-maxdepth`/`-mindepth` は BSD find (macOS) と GNU find (Linux) の両方でサポートされており、対象環境では問題なく動作します。\n\nPR description の「POSIX 互換」という表現は不正確でしたので修正します。"}) {
    comment { id }
  }
}'

gh api graphql -F query='
mutation {
  resolveReviewThread(input: {threadId: "PRRT_kwDOQFge-M51rND6"}) {
    thread { isResolved }
  }
}'

