# スレッド 3 (gemini L157): 空ディレクトリのクリーンアップバグ修正 + ls -A は POSIX
gh api repos/ronnnnn/cc/pulls/comments/2964883747/reactions -f content="+1" > /dev/null 2>&1

gh api graphql -F query='
mutation {
  addPullRequestReviewThreadReply(input: {pullRequestReviewThreadId: "PRRT_kwDOQFge-M51rNGF", body: "空の `WORK_TMPDIR` が削除されないバグのご指摘ありがとうございます。`rm -rf` を条件の外に移動し、内容の有無に関わらずクリーンアップが実行されるよう修正しました (a8bac0b)。\n\nなお、`ls -A` について補足します。`ls -A` は GNU 拡張ではなく POSIX.1 仕様に含まれています (SD5-XCU-ERN-50 で追加)。\nref: https://pubs.opengroup.org/onlinepubs/9699919799/utilities/ls.html\n\nそのため `ls -A` の置き換えは不要と判断し、現状のまま維持します。"}) {
    comment { id }
  }
}'

gh api graphql -F query='
mutation {
